            import hashlib
            addr = address[2:]  # strip 0x
            addr_hash = hashlib.sha3_256(addr.lower().encode()).hexdigest()
            for i, char in enumerate(addr):
                if char.isalpha():
                    if int(addr_hash[i], 16) >= 8 and char != char.upper():
                        return False
                    if int(addr_hash[i], 16) < 8 and char != char.lower():
                        return False
        except Exception:
            return False
    return True
```

